const variableNames = [
    "crane/arduino/weight",
    "crane/arduino/calibration",
    "crane/fault",
    "crane/speed_mode",
    "crane/electromagnet",
    "crane/detectors/left",
    "crane/detectors/right",
    "crane/allow_remote",
    "crane/motor_horizontal/power",
    "crane/motor_horizontal/velocity",
    "crane/motor_horizontal/specified/distance",
    "crane/motor_horizontal/specified/movement",
    "crane/motor_horizontal/continuous",
    "crane/motor_horizontal/actual_position",
    "crane/motor_vertical/power",
    "crane/motor_vertical/velocity",
    "crane/motor_vertical/specified/distance",
    "crane/motor_vertical/specified/movement",
    "crane/motor_vertical/continuous",
    "crane/motor_vertical/actual_position",
    "crane/process_status",
    "crane/motor_horizontal/limits",
    "crane/motor_vertical/limits",
    "crane/cargo",
    "crane/control/up",
    "crane/control/down",
    "crane/control/left",
    "crane/control/right"
];

let word1 = 0xFF;
let word2 = 0xFF;
let value = 0xFF;

if (msg.payload.length >= variableNames.length * 2) 
{

    let buf = Buffer.alloc(4);

    for (let i = 0; i < variableNames.length; i++) 
    {
        word1 = msg.payload[i * 2];
        word2 = msg.payload[(i * 2) + 1];

        buf.writeUInt16BE(word1, 0);
        buf.writeUInt16BE(word2, 2);

        switch (i)
        {
            case 0:
            case 9:
            case 10:
            case 13:
            case 15:
            case 16:
            case 19:
                value = buf.readFloatBE(0);
            break;

            default:
                value = buf.readInt32BE(0);
            break;
        }

        flow.set(variableNames[i], value);
    }


    return msg;

} 
else 
{
    node.error(`Not enough Modbus data. Expected ${variableNames.length * 2} words.`, msg);
    return null;
}

const publishMap = [
    "crane/arduino/weight",
    "crane/arduino/calibration",
    "crane/fault",
    "crane/speed_mode",
    "crane/electromagnet",
    "crane/detectors/left",
