    "crane/motor_vertical/continuous",
    "crane/motor_vertical/actual_position",
    "crane/process_status",
    "crane/motor_horizontal/limits",
    "crane/motor_vertical/limits",
    "crane/cargo",
    "crane/control/up",
    "crane/control/down",
    "crane/control/left",
    "crane/control/right"
];

let previousValues = flow.get('prevValues') || {};
let lastSentTimes = flow.get('lastSentTimes') || {};
let messagesToSend = [];
const now = Date.now();
const FORCE_SEND_INTERVAL = 60000;

for (let item of publishMap) {
    let currentValue = flow.get(item);
    let lastTime = lastSentTimes[item] || 0;

    if (previousValues[item] !== currentValue || (now - lastTime) >= FORCE_SEND_INTERVAL) {

        previousValues[item] = currentValue;
        lastSentTimes[item] = now; // Update the timestamp for this topic

        messagesToSend.push({
            topic: item,
            payload: currentValue
        });
    }
}

flow.set('prevValues', previousValues);
flow.set('lastSentTimes', lastSentTimes);

if (messagesToSend.length > 0) {
    return [messagesToSend];
} else {
    return null;
}

